--- /dev/null
+++ b/internal/uri/shortescape_test.go
@@
+package uri_test
+
+import (
+	"testing"
+
+	"github.com/dleblanc/kindling/internal/uri"
+)
+
+func TestPercentDecodeShortEscapeAtEnd(t *testing.T) {
+	for _, in := range []string{"%", "%A", "%a", "%z", "ab%", "ab%C"} {
+		if _, err := uri.PercentDecode([]byte(in)); err == nil {
+			t.Errorf("PercentDecode(%q): expected short-escape error, got nil", in)
+		}
+	}
+}
+
+func TestPercentDecodeValidBeforeEnd(t *testing.T) {
+	out, err := uri.PercentDecode([]byte("a%20"))
+	if err != nil {
+		t.Fatalf("unexpected error: %v", err)
+	}
+	if string(out) != "a " {
+		t.Errorf("got %q", out)
+	}
+}
